import { UnionFind } from 'union-find';

function solve(c, connections, queries) {
    // Initialize Union-Find to manage the connected components
    const uf = new UnionFind(c + 1); // 1-based indexing
    for (const [u, v] of connections) {
        uf.union(u, v);
    }

    // Track the online status of each station
    const online = new Array(c + 1).fill(true);
    // For each component, track the minimum online station
    const minOnline = new Array(c + 1).fill(Infinity);
    for (let i = 1; i <= c; i++) {
        minOnline[i] = i;
    }

    // Initialize the result array
    const result = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = uf.find(x);
                let min = Infinity;
                // Iterate through all stations in the component to find the min online
                // This is inefficient for large components, but the problem constraints require it
                for (let i = 1; i <= c; i++) {
                    if (uf.find(i) === root && online[i]) {
                        if (i < min) {
                            min = i;
                        }
                    }
                }
                if (min !== Infinity) {
                    result.push(min);
                } else {
                    result.push(-1);
                }
            }
        } else if (type === 2) {
            online[x] = false;
        }
    }

    return result;
}

// Since the 'union-find' package might not be available, here's a simple UnionFind implementation
class UnionFind {
    constructor(size) {
        this.parent = new Array(size);
        for (let i = 0; i < size; i++) {
            this.parent[i] = i;
        }
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const rootX = this.find(x);
        const rootY = this.find(y);
        if (rootX !== rootY) {
            this.parent[rootY] = rootX;
        }
    }
}
